class Solution:
    def numberOfWays(self, n, x):
        MOD = 10 ** 9 + 7
        powers = []
        i = 1
        while i ** x <= n:
            powers.append(i ** x)
            i += 1
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def rec(idx, remaining):
            if remaining == 0:
                return 1
            if idx == len(powers) or remaining < 0:
                return 0
            return (rec(idx + 1, remaining) + rec(idx + 1, remaining - powers[idx])) % MOD

        result = rec(0, n) % MOD
        rec.cache_clear()
        return result

