var numberOfWays = function(n, x) {
    const MOD = 1000000007;
    const powers = [];
    let i = 1;
    while (Math.pow(i, x) <= n) {
        powers.push(Math.pow(i, x));
        i++;
    }
    const dp = new Array(n + 1).fill(0);
    dp[0] = 1;
    for (const p of powers) {
        for (let s = n; s >= p; s--) {
            dp[s] = (dp[s] + dp[s - p]) % MOD;
        }
    }
    return dp[n] % MOD;
};
